  89→const TAG_COLOR_NAMES = new Set<string>(Object.keys(TAG_COLOR_HEX));
  90→
  91→function isTagColor(value: string): value is TagColor {
  92→  return TAG_COLOR_NAMES.has(value);
  93→}
  94→
  95→function isQuicklinkType(value: string): value is QuicklinkType {
  96→  return value === 'url' || value === 'file' || value === 'deeplink';
  97→}
  98→
  99→function rowToEntry(row: QuicklinkRow): QuicklinkEntry {
 100→  const parsed = new Date(row.created_at);
 101→  const createdAt = Number.isNaN(parsed.getTime()) ? new Date() : parsed;
 102→  const type = isQuicklinkType(row.type) ? row.type : 'url';
 103→
 104→  let tags:
 105→    | {
 106→        text: string;
 107→        color?: TagColor;
 108→      }[]
 109→    | undefined;
 110→  if (row.tags) {
 111→    try {
 112→      const parsed = JSON.parse(row.tags);
 113→      if (Array.isArray(parsed)) {
 114→        tags = parsed
 115→          .filter(
 116→            (
 117→              t,
 118→            ): t is {
 119→              text: string;
 120→              color?: string;
 121→            } =>
 122→              typeof t === 'object' && t !== null && typeof t.text === 'string',
 123→          )
 124→          .map(t => ({
 125→            text: t.text,
 126→            color:
 127→              typeof t.color === 'string' && isTagColor(t.color)
 128→                ? t.color
 129→                : undefined,
 130→          }));
 131→      }
 132→    } catch {
 133→      // invalid JSON — ignore tags
 134→    }
 135→  }
 136→
 137→  return {
 138→    id: row.id,
 139→    name: row.name,
 140→    link: row.link,
 141→    type,
 142→    application: row.application ?? undefined,
 143→    icon: getQuicklinkIcon(type),
 144→    tags,
 145→    createdAt,
 146→  };
 147→}
 148→
 149→function entryToRow(entry: QuicklinkEntry): QuicklinkRow {
 150→  return {
 151→    id: entry.id,
 152→    name: entry.name,
 153→    link: entry.link,
 154→    type: entry.type,
 155→    application: entry.application ?? null,
 156→    tags: entry.tags ? JSON.stringify(entry.tags) : '[]',
 157→    created_at: entry.createdAt.toISOString(),
 158→  };
 159→}
