 237→function resolveIcon(iconChoice: IconChoice, type: QuicklinkType): ReactNode {
 238→  if (iconChoice === 'auto') return getQuicklinkIcon(type);
 239→  if (isQuicklinkType(iconChoice)) return getQuicklinkIcon(iconChoice);
 240→  return getQuicklinkIcon(type);
 241→}
