 258→interface EditQuicklinkViewProps {
 259→  quicklink?: QuicklinkEntry;
 260→  onSubmit: (form: QuicklinkFormState) => void;
 261→}
 262→
 263→function EditQuicklinkView({ quicklink, onSubmit }: EditQuicklinkViewProps) {
 264→  const [form, setForm] = useState<QuicklinkFormState>(() => {
 265→    if (quicklink) {
 266→      return {
 267→        name: quicklink.name,
 268→        link: quicklink.link,
 269→        type: quicklink.type,
 270→        iconChoice: 'auto',
 271→        application: quicklink.application ?? '',
 272→      };
 273→    }
 274→    return INITIAL_FORM;
 275→  });
 276→  const [errors, setErrors] = useState<
 277→    Partial<Record<keyof QuicklinkFormState, string>>
 278→  >({});
 279→
 280→  const handleSubmit = useCallback(() => {
 281→    const newErrors: Partial<Record<keyof QuicklinkFormState, string>> = {};
 282→    if (!form.name.trim()) {
 283→      newErrors.name = 'Name is required';
 284→    }
 285→    if (!form.link.trim()) {
 286→      newErrors.link = 'Link is required';
 287→    }
 288→    setErrors(newErrors);
 289→    if (Object.keys(newErrors).length > 0) return;
 290→    onSubmit(form);
 291→  }, [
 292→    form,
 293→    onSubmit,
 294→  ]);
 295→
 296→  useKeyboardShortcut(
 297→    {
 298→      key: 'Enter',
 299→      meta: true,
 300→    },
 301→    handleSubmit,
 302→  );
 303→
 304→  return (
 305→    <Form onSubmit={handleSubmit}>
 306→      <FormTextField
 307→        label="Name"
 308→        value={form.name}
 309→        onChange={v =>
 310→          setForm(prev => ({
 311→            ...prev,
 312→            name: v,
 313→          }))
 314→        }
 315→        placeholder="e.g. GitHub Dashboard"
 316→        error={errors.name}
 317→        autoFocus
 318→      />
 319→      <FormTextField
 320→        label="Link"
 321→        value={form.link}
 322→        onChange={v =>
 323→          setForm(prev => ({
 324→            ...prev,
 325→            link: v,
 326→          }))
 327→        }
 328→        placeholder="e.g. https://github.com or ~/Documents"
 329→        description="Use {query} as placeholder for dynamic input"
 330→        error={errors.link}
 331→      />
 332→      <FormDropdown
 333→        label="Type"
 334→        value={form.type}
 335→        onChange={v => {
 336→          if (isQuicklinkType(v)) {
 337→            setForm(prev => ({
 338→              ...prev,
 339→              type: v,
 340→            }));
 341→          }
 342→        }}
 343→        options={TYPE_OPTIONS}
 344→      />
 345→      <FormDropdown
 346→        label="Icon"
 347→        value={form.iconChoice}
 348→        onChange={v => {
 349→          if (isIconChoice(v)) {
 350→            setForm(prev => ({
 351→              ...prev,
 352→              iconChoice: v,
 353→            }));
 354→          }
 355→        }}
 356→        options={ICON_OPTIONS}
 357→      />
 358→      <FormTextField
 359→        label="Open With"
 360→        value={form.application}
 361→        onChange={v =>
 362→          setForm(prev => ({
 363→            ...prev,
 364→            application: v,
 365→          }))
 366→        }
 367→        placeholder="e.g. Safari (optional)"
 368→        description="Application to open the link with"
 369→      />
 370→    </Form>
 371→  );
 372→}
