 380→function QueryInputView({
 381→  quicklink,
 382→  onSubmit,
 383→  onCancel,
 384→}: QueryInputViewProps) {
 385→  const [inputValue, setInputValue] = useState('');
 386→
 387→  const handleSubmit = useCallback(() => {
 388→    if (!inputValue.trim()) return;
 389→    const resolved = quicklink.link.replaceAll(
 390→      '{query}',
 391→      encodeURIComponent(inputValue.trim()),
 392→    );
 393→    onSubmit(resolved);
 394→  }, [
 395→    inputValue,
 396→    quicklink.link,
 397→    onSubmit,
 398→  ]);
 399→
 400→  useKeyboardShortcut(
 401→    {
 402→      key: 'Enter',
 403→      meta: true,
 404→    },
 405→    handleSubmit,
 406→  );
 407→  useKeyboardShortcut({ key: 'Escape' }, onCancel);
 408→
 409→  return (
 410→    <Form onSubmit={handleSubmit}>
 411→      <FormTextField
 412→        label="Query"
 413→        value={inputValue}
 414→        onChange={setInputValue}
 415→        placeholder={`Enter query for ${quicklink.name}...`}
 416→        description={`Opens: ${quicklink.link.replace('{query}', '<your input>')}`}
 417→        autoFocus
 418→      />
 419→    </Form>
 420→  );
 421→}
