 423→function openQuicklink(link: string, type: QuicklinkType) {
 424→  switch (type) {
 425→    case 'url':
 426→      openUrl(link);
 427→      break;
 428→    case 'deeplink':
 429→      openDeepLink(link);
 430→      break;
 431→    case 'file':
 432→      openDeepLink(`file://${link}`);
 433→      break;
 434→  }
 435→}
